using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Label")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedChurned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

arguments.old_str:
var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();
app.MapGet("/", () => "Hello");
app.Run();

arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// Train the model and register the pooled prediction engine
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features", nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate on the test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

// Save the model and register PredictionEnginePool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedChurned,
        probability = prediction.Probability,
    });
});

app.Run();

record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

